#!/usr/bin/env python3
"""crosswalk_generator.py — produce a framework coverage matrix from a YAML control library."""

import yaml
import json
from collections import defaultdict
from pathlib import Path

FRAMEWORKS = ["nist_ai_rmf", "iso_42001", "soc2", "eu_ai_act"]

def load_controls(library_path: Path) -> list[dict]:
    with library_path.open() as f:
        return yaml.safe_load(f)["controls"]

def build_coverage_matrix(controls: list[dict]) -> dict:
    """
    Returns a dict mapping each framework to its set of satisfied requirements.
    coverage_matrix[framework] = {req_id: [control_ids that satisfy it]}
    """
    matrix = {fw: defaultdict(list) for fw in FRAMEWORKS}
    for control in controls:
        refs = control.get("framework_refs", {})
        for fw in FRAMEWORKS:
            for req in refs.get(fw, []):
                matrix[fw][req].append(control["id"])
    return {fw: dict(reqs) for fw, reqs in matrix.items()}

def compute_gap_register(controls: list[dict]) -> list[dict]:
    """
    Controls whose framework_refs are empty or below a minimum threshold
    represent agent-specific gaps not covered by standard frameworks.
    """
    gaps = []
    for control in controls:
        refs = control.get("framework_refs", {})
        total_refs = sum(len(v) for v in refs.values())
        if total_refs == 0:
            gaps.append({
                "control_id": control["id"],
                "title": control["title"],
                "gap_type": "no_framework_coverage",
                "recommendation": "Author supplemental evidence memo for auditors",
            })
        elif "coverage_notes" in control and "gap" in control["coverage_notes"].lower():
            gaps.append({
                "control_id": control["id"],
                "title": control["title"],
                "gap_type": "partial_framework_coverage",
                "recommendation": control["coverage_notes"],
            })
    return gaps

def generate_crosswalk_report(library_path: Path, out_path: Path):
    controls = load_controls(library_path)
    matrix = build_coverage_matrix(controls)
    gaps = compute_gap_register(controls)

    # Compute coverage percentages (using known requirement counts per framework)
    known_req_counts = {
        "nist_ai_rmf": 72,   # approximate sub-function count
        "iso_42001":   45,
        "soc2":        33,   # Trust Services Criteria count
        "eu_ai_act":   28,   # high-risk requirements
    }
    coverage_pct = {
        fw: round(len(matrix[fw]) / known_req_counts[fw] * 100, 1)
        for fw in FRAMEWORKS
    }

    report = {
        "generated_at": "2025-01-01",
        "total_controls": len(controls),
        "framework_coverage_pct": coverage_pct,
        "coverage_matrix": matrix,
        "gap_register": gaps,
    }
    with out_path.open("w") as f:
        json.dump(report, f, indent=2)
    print(f"Crosswalk report written to {out_path}")
    for fw, pct in coverage_pct.items():
        status = "OK" if pct >= 70 else "BELOW TARGET"
        print(f"  {fw}: {pct}% ({status})")
    print(f"  Gaps identified: {len(gaps)}")

if __name__ == "__main__":
    generate_crosswalk_report(
        Path("./control-library.yaml"),
        Path("./crosswalk-report.json"),
    )

